import React, { useState, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  CircularProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import EmailIcon from '@mui/icons-material/Email';
import PersonIcon from '@mui/icons-material/Person';

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Interactive demo state
  const [demoStage, setDemoStage] = useState(0);
  const [demoInput, setDemoInput] = useState("The coaching was good. I learned some things that helped me.");
  const [isProcessing, setIsProcessing] = useState(false);
  const [enhancedText, setEnhancedText] = useState("");
  const [clientName, setClientName] = useState("");
  const [clientEmail, setClientEmail] = useState("");
  const [showApproval, setShowApproval] = useState(false);
  const [isApproved, setIsApproved] = useState(false);

  // Enhanced testimonial examples
  const enhancedExample = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  // Auto-advance demo stages
  useEffect(() => {
    if (demoStage === 0) {
      // Auto-start the demo after 2 seconds
      const timer = setTimeout(() => {
        handleEnhance();
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [demoStage]);

  const handleEnhance = () => {
    if (demoStage === 0) {
      setIsProcessing(true);
      // Simulate API processing
      setTimeout(() => {
        setEnhancedText(enhancedExample);
        setIsProcessing(false);
        setDemoStage(1);
      }, 2500);
    }
  };

  const handleSendApproval = () => {
    if (demoStage === 1) {
      setIsProcessing(true);
      // Simulate sending approval request
      setTimeout(() => {
        setIsProcessing(false);
        setDemoStage(2);
        setShowApproval(true);
      }, 1500);
    }
  };

  const handleApprove = () => {
    setIsApproved(true);
    // Simulate approval animation
    setTimeout(() => {
      setDemoStage(3);
    }, 1000);
  };

  const resetDemo = () => {
    setDemoStage(0);
    setIsProcessing(false);
    setEnhancedText("");
    setClientName("");
    setClientEmail("");
    setShowApproval(false);
    setIsApproved(false);
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 8, md: 10 },
          pb: { xs: 10, md: 12 },
          position: 'relative',
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg">
          <Grid container spacing={6} alignItems="center">
            {/* Left side - Hero text */}
            <Grid item xs={12} md={6}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography variant="h1" gutterBottom>
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  endIcon={<ArrowForwardIcon />}
                  sx={{ px: 3, py: 1.5 }}
                >
                  Enhance a Testimonial
                </Button>
                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ px: 3, py: 1.5 }}
                >
                  See How It Works
                </Button>
              </Stack>

              <Box sx={{ mt: 4, display: 'flex', alignItems: 'center' }}>
                <Box sx={{ display: 'flex' }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="body2" sx={{ ml: 1, fontWeight: 500 }}>
                  4.9/5 from 200+ users
                </Typography>
              </Box>
            </Grid>

            {/* Right side - Interactive Demo */}
            <Grid item xs={12} md={6}>
              <Card 
                elevation={0} 
                sx={{ 
                  borderRadius: 4,
                  overflow: 'hidden',
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  boxShadow: '0 10px 40px rgba(0, 0, 0, 0.08)',
                  position: 'relative',
                  minHeight: 480,
                  background: '#ffffff',
                  transition: 'all 0.3s ease',
                }}
              >
                {/* Demo Header */}
                <Box sx={{ 
                  p: 2, 
                  borderBottom: '1px solid rgba(0, 0, 0, 0.06)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'space-between'
                }}>
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <Box 
                      sx={{ 
                        width: 12, 
                        height: 12, 
                        borderRadius: '50%', 
                        bgcolor: '#FF5F57',
                        mr: 1 
                      }} 
                    />
                    <Box 
                      sx={{ 
                        width: 12, 
                        height: 12, 
                        borderRadius: '50%', 
                        bgcolor: '#FFBD2E',
                        mr: 1 
                      }} 
                    />
                    <Box 
                      sx={{ 
                        width: 12, 
                        height: 12, 
                        borderRadius: '50%', 
                        bgcolor: '#28CA41',
                        mr: 1 
                      }} 
                    />
                  </Box>
                  <Typography variant="caption" color="text.secondary">
                    {demoStage === 0 && "Step 1: Enter Testimonial"}
                    {demoStage === 1 && "Step 2: Review Enhanced Version"}
                    {demoStage === 2 && "Step 3: Client Approval"}
                    {demoStage === 3 && "Testimonial Approved!"}
                  </Typography>
                  <Button 
                    size="small" 
                    variant="text" 
                    onClick={resetDemo}
                    sx={{ minWidth: 'auto', p: 0.5 }}
                  >
                    Reset
                  </Button>
                </Box>

                {/* Demo Content */}
                <Box sx={{ p: 3 }}>
                  {/* Stage 0: Original Testimonial Input */}
                  {demoStage === 0 && (
                    <Fade in={demoStage === 0}>
                      <Box>
                        <Typography variant="h6" gutterBottom>
                          Enter your client's testimonial
                        </Typography>
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                          Even if it's brief or bland, our AI will extract the value
                        </Typography>

                        <TextField
                          multiline
                          rows={4}
                          fullWidth
                          variant="outlined"
                          value={demoInput}
                          onChange={(e) => setDemoInput(e.target.value)}
                          disabled={isProcessing}
                          sx={{ mb: 3 }}
                        />

                        <Button
                          variant="contained"
                          color="primary"
                          fullWidth
                          onClick={handleEnhance}
                          disabled={isProcessing}
                          sx={{ py: 1.5 }}
                        >
                          {isProcessing ? (
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              <CircularProgress size={20} color="inherit" sx={{ mr: 1 }} />
                              Enhancing...
                            </Box>
                          ) : (
                            <>Enhance with AI</>
                          )}
                        </Button>
                      </Box>
                    </Fade>
                  )}

                  {/* Stage 1: Enhanced Testimonial */}
                  {demoStage === 1 && (
                    <Fade in={demoStage === 1}>
                      <Box>
                        <Typography variant="h6" gutterBottom>
                          Your enhanced testimonial
                        </Typography>

                        <Paper 
                          elevation={0} 
                          sx={{ 
                            p: 2, 
                            mb: 3, 
                            bgcolor: 'grey.50',
                            borderRadius: 2
                          }}
                        >
                          <Typography variant="body2" color="text.secondary" gutterBottom>
                            Original:
                          </Typography>
                          <Typography variant="body2">
                            {demoInput}
                          </Typography>
                        </Paper>

                        <Paper 
                          elevation={0} 
                          sx={{ 
                            p: 2, 
                            mb: 3, 
                            bgcolor: 'primary.light',
                            borderRadius: 2
                          }}
                        >
                          <Typography variant="body2" color="primary.dark" gutterBottom>
                            Enhanced:
                          </Typography>
                          <Typography variant="body2" color="primary.dark" sx={{ fontWeight: 500 }}>
                            {enhancedText}
                          </Typography>
                        </Paper>

                        <Button
                          variant="contained"
                          color="primary"
                          fullWidth
                          onClick={handleSendApproval}
                          disabled={isProcessing}
                          sx={{ py: 1.5 }}
                        >
                          {isProcessing ? (
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              <CircularProgress size={20} color="inherit" sx={{ mr: 1 }} />
                              Sending...
                            </Box>
                          ) : (
                            <>Send for Client Approval</>
                          )}
                        </Button>
                      </Box>
                    </Fade>
                  )}

                  {/* Stage 2: Client Approval View */}
                  {demoStage === 2 && (
                    <Fade in={demoStage === 2}>
                      <Box>
                        <Typography variant="h6" gutterBottom>
                          Client Approval View
                        </Typography>
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                          Your client will see this page to approve the testimonial
                        </Typography>

                        <Box sx={{ 
                          p: 3, 
                          border: '1px dashed rgba(0, 0, 0, 0.1)', 
                          borderRadius: 2,
                          mb: 3,
                          bgcolor: 'background.paper'
                        }}>
                          <Typography variant="subtitle1" gutterBottom>
                            Please review your enhanced testimonial
                          </Typography>

                          <Box sx={{ mb: 3 }}>
                            <Typography variant="body2" color="text.secondary" gutterBottom>
                              Original:
                            </Typography>
                            <Typography variant="body2" sx={{ mb: 2 }}>
                              {demoInput}
                            </Typography>

                            <Typography variant="body2" color="text.secondary" gutterBottom>
                              Enhanced:
                            </Typography>
                            <Typography variant="body2" sx={{ fontWeight: 500 }}>
                              {enhancedText}
                            </Typography>
                          </Box>

                          <Button
                            variant="contained"
                            color="success"
                            fullWidth
                            onClick={handleApprove}
                            startIcon={<CheckCircleIcon />}
                            sx={{ py: 1.5, mb: 1 }}
                          >
                            {isApproved ? "Approved!" : "Yes, I Approve This Testimonial"}
                          </Button>
                        </Box>
                      </Box>
                    </Fade>
                  )}

                  {/* Stage 3: Success */}
                  {demoStage === 3 && (
                    <Fade in={demoStage === 3}>
                      <Box sx={{ textAlign: 'center', py: 4 }}>
                        <CheckCircleIcon sx={{ fontSize: 60, color: 'success.main', mb: 2 }} />
                        <Typography variant="h5" gutterBottom>
                          Testimonial Approved!
                        </Typography>
                        <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
                          Your enhanced testimonial is ready to use
                        </Typography>

                        <Button
                          variant="contained"
                          color="primary"
                          onClick={resetDemo}
                          sx={{ px: 3, py: 1.5 }}
                        >
                          Try Another Example
                        </Button>
                      </Box>
                    </Fade>
                  )}
                </Box>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: 'grey.50' }}>
        <Container maxWidth="lg">
          <Typography variant="h2" align="center" gutterBottom>
            How It Works
          </Typography>
          <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 8, maxWidth: 700, mx: 'auto' }}>
            Transform bland testimonials into powerful stories in three simple steps
          </Typography>

          <Grid container spacing={4}>
            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
